"use client";
import React, { useState, useEffect } from 'react';
import { MapPin, Mail, Phone, Facebook, Twitter, Instagram, Menu, X, Search, User, Sprout, ChevronDown } from 'lucide-react';
import Link from 'next/link';

export default function MorviNavbar() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [showProducts, setShowProducts] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const productsList = [
    "GO-ON", "HITLER", "KAWACH", "SHAKTI PLUS", 
    "BLACK-TIGER", "ROOT MAKER", "MAIZE SEED", "VILTO MAX GOLD"
  ];

  return (
    <div className="w-full">
      {/* Top Bar - Orange Gradient */}
      <div className="bg-gradient-to-r from-[#ff9c00] via-[#ff8800] to-[#ff9c00] text-white py-3 shadow-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-wrap items-center justify-between text-sm">
            {/* Left Side - Contact Info */}
            <div className="flex flex-wrap items-center gap-4 lg:gap-6">
              <div className="flex items-center gap-2 hover:scale-105 transition-transform">
                <MapPin className="w-4 h-4" />
                <span className="hidden sm:inline">Samudragarh, West Bengal</span>
              </div>
              <div className="flex items-center gap-2 hover:scale-105 transition-transform">
                <Mail className="w-4 h-4" />
                <Link href="mailto:morvicropscience@gmail.com" className="hidden md:inline hover:underline">
                  morvicropscience@gmail.com
                </Link>
              </div>
              <div className="flex items-center gap-2 hover:scale-105 transition-transform">
                <Phone className="w-4 h-4" />
                <Link href="tel:+917987279783" className="hover:underline">+91 7987279783</Link>
              </div>
            </div>

            {/* Right Side - Social Media */}
            <div className="flex items-center gap-4">
              <span className="hidden sm:inline font-semibold">Follow Us:</span>
              <div className="flex items-center gap-3">
                <Link href="#" className="w-8 h-8 bg-white/20 hover:bg-white/30 rounded-full flex items-center justify-center transition-all hover:scale-110">
                  <Facebook className="w-4 h-4" />
                </Link>
                <Link href="#" className="w-8 h-8 bg-white/20 hover:bg-white/30 rounded-full flex items-center justify-center transition-all hover:scale-110">
                  <Twitter className="w-4 h-4" />
                </Link>
                <Link href="#" className="w-8 h-8 bg-white/20 hover:bg-white/30 rounded-full flex items-center justify-center transition-all hover:scale-110">
                  <Instagram className="w-4 h-4" />
                </Link>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Main Navigation Bar */}
      <nav className={`bg-white shadow-lg sticky top-0 z-50 transition-all duration-300 ${scrolled ? 'shadow-xl' : ''}`}>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-24">
            {/* Logo */}
            <div className="flex items-center space-x-4">
              <div className="relative group">
                {/* Animated circular logo */}
                <div className="w-20 h-20 rounded-full border-4 border-green-600 flex items-center justify-center bg-gradient-to-br from-green-50 to-white relative overflow-hidden group-hover:border-[#ff9c00] transition-all duration-300 shadow-lg">
                  <Sprout className="w-10 h-10 text-green-600 group-hover:text-[#ff9c00] transition-colors duration-300" />
                  {/* Decorative circle */}
                  <div className="absolute -top-2 -right-2 w-8 h-8 bg-gradient-to-br from-green-600 to-[#ff9c00] rounded-full flex items-center justify-center shadow-md">
                    <div className="w-4 h-4 bg-white rounded-full"></div>
                  </div>
                </div>
              </div>
              <div>
                <h1 className="text-xl lg:text-2xl font-extrabold bg-gradient-to-r from-green-600 to-[#ff9c00] bg-clip-text text-transparent">
                 MORVI CROP SCIENCE PRIVATE LIMITED
                </h1>
                <p className="text-xs lg:text-sm text-gray-600 font-semibold">
                  कृषि उत्कृष्टता | Agricultural Excellence
                </p>
              </div>
            </div>

            {/* Desktop Navigation */}
            <div className="hidden lg:flex items-center space-x-2">
              <Link href="/" className="relative px-4 py-2 text-white bg-gradient-to-r from-green-600 to-green-700 rounded-lg font-semibold shadow-md hover:shadow-lg transition-all">
                Home
              </Link>
              <Link href="/about" className="px-4 py-2 text-gray-700 hover:text-white hover:bg-gradient-to-r hover:from-green-600 hover:to-green-700 rounded-lg font-semibold transition-all">
                About Us
              </Link>
              
              {/* Products Dropdown */}
              <div 
                className="relative"
                onMouseEnter={() => setShowProducts(true)}
                onMouseLeave={() => setShowProducts(false)}
              >
                <button className="px-4 py-2 text-gray-700 hover:text-white hover:bg-gradient-to-r hover:from-green-600 hover:to-green-700 rounded-lg font-semibold transition-all flex items-center gap-1">
                  Products
                  <ChevronDown className={`w-4 h-4 transition-transform ${showProducts ? 'rotate-180' : ''}`} />
                </button>
                
                {/* Dropdown Menu */}
                {showProducts && (
                  <div className="absolute top-full left-0 mt-2 w-64 bg-white rounded-xl shadow-2xl border border-gray-100 py-2 animate-fade-in">
                    <div className="px-4 py-2 bg-gradient-to-r from-green-50 to-orange-50 border-b border-gray-100">
                      <p className="text-sm font-bold text-gray-900">Our Products</p>
                    </div>
                    <div className="max-h-96 overflow-y-auto">
                      {productsList.map((product, idx) => (
                        <a 
                          key={idx}
                          href={`/products/${product.toLowerCase().replace(' ', '-')}`}
                          className="block px-4 py-3 text-gray-700 hover:bg-gradient-to-r hover:from-green-50 hover:to-orange-50 hover:text-green-700 transition-all border-l-4 border-transparent hover:border-[#ff9c00]"
                        >
                          <span className="font-medium">{product}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
              
              <a href="/contact" className="px-4 py-2 text-gray-700 hover:text-white hover:bg-gradient-to-r hover:from-green-600 hover:to-green-700 rounded-lg font-semibold transition-all">
                Contact
              </a>
            </div>

            {/* Right Side Icons & Button */}
            <div className="hidden lg:flex items-center space-x-3">
              <button className="p-3 hover:bg-gradient-to-br hover:from-green-50 hover:to-orange-50 rounded-full transition-all group">
                <Search className="w-5 h-5 text-gray-700 group-hover:text-green-600" />
              </button>
              <button className="p-3 hover:bg-gradient-to-br hover:from-green-50 hover:to-orange-50 rounded-full transition-all group">
                <User className="w-5 h-5 text-gray-700 group-hover:text-green-600" />
              </button>
              <button className="bg-gradient-to-r from-[#ff9c00] to-[#ff8800] hover:from-[#ff8800] hover:to-[#ff9c00] text-white px-8 py-3 rounded-full font-bold transition-all transform hover:scale-105 shadow-lg hover:shadow-xl">
                Get A Quote
              </button>
            </div>

            {/* Mobile Menu Button */}
            <button 
              className="lg:hidden p-2 rounded-lg hover:bg-gray-100 transition-colors"
              onClick={() => setIsMenuOpen(!isMenuOpen)}
            >
              {isMenuOpen ? (
                <X className="w-7 h-7 text-gray-700" />
              ) : (
                <Menu className="w-7 h-7 text-gray-700" />
              )}
            </button>
          </div>

          {/* Mobile Menu */}
          {isMenuOpen && (
            <div className="lg:hidden py-4 border-t border-gray-200 animate-slide-down">
              <div className="flex flex-col space-y-3">
                <Link href="/" className="text-white bg-gradient-to-r from-green-600 to-green-700 font-semibold px-4 py-3 rounded-lg shadow-md">
                  Home
                </Link>
                <Link href="/about" className="text-gray-700 hover:text-green-600 font-semibold px-4 py-3 hover:bg-green-50 rounded-lg transition-all">
                  About Us
                </Link>
                <div className="px-4 py-2">
                  <button 
                    onClick={() => setShowProducts(!showProducts)}
                    className="w-full text-left text-gray-700 hover:text-green-600 font-semibold py-2 flex items-center justify-between"
                  >
                    Products
                    <ChevronDown className={`w-4 h-4 transition-transform ${showProducts ? 'rotate-180' : ''}`} />
                  </button>
                  {showProducts && (
                    <div className="mt-2 pl-4 space-y-2 border-l-2 border-[#ff9c00]">
                      {productsList.slice(0, 4).map((product, idx) => (
                        <Link 
                          key={idx}
                          href={`/products/${product.toLowerCase().replace(' ', '-')}`}
                          className="block text-sm text-gray-600 hover:text-green-600 py-1"
                        >
                          {product}
                        </Link>
                      ))}
                      <Link href="/products" className="block text-sm text-[#ff9c00] font-semibold py-1">
                        View All Products →
                      </Link>
                    </div>
                  )}
                </div>
                <Link href="/contact" className="text-gray-700 hover:text-green-600 font-semibold px-4 py-3 hover:bg-green-50 rounded-lg transition-all">
                  Contact
                </Link>
                <div className="flex items-center gap-3 px-4 pt-4 border-t border-gray-200">
                  <button className="p-3 hover:bg-green-50 rounded-full transition-all">
                    <Search className="w-5 h-5 text-gray-700" />
                  </button>
                  <button className="p-3 hover:bg-green-50 rounded-full transition-all">
                    <User className="w-5 h-5 text-gray-700" />
                  </button>
                  <button className="bg-gradient-to-r from-[#ff9c00] to-[#ff8800] text-white px-6 py-3 rounded-full font-bold flex-1 shadow-md">
                    Get A Quote
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </nav>

      <style jsx>{`
        @keyframes fade-in {
          from {
            opacity: 0;
            transform: translateY(-10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
        
        @keyframes slide-down {
          from {
            opacity: 0;
            max-height: 0;
          }
          to {
            opacity: 1;
            max-height: 500px;
          }
        }
        
        .animate-fade-in {
          animation: fade-in 0.3s ease-out;
        }
        
        .animate-slide-down {
          animation: slide-down 0.3s ease-out;
        }
      `}</style>
    </div>
  );
}