"use client";
import React, { useState } from 'react';
import Link from 'next/link';
import { FaFacebookF, FaTwitter, FaHome, FaCaretDown, FaBars, FaTimes, FaUser } from 'react-icons/fa';

const Navbarr = () => {
    // State to handle mobile menu toggle
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    return (
        <div className="w-full font-sans">

            {/* --- Top Bar (Gray Section) --- */}
            <div className="bg-gray-100 border-b border-gray-200 text-xs md:text-sm py-1 px-4 md:px-10 flex justify-between items-center text-gray-700">
                <div className="font-semibold text-green-800">
                   Agricultural Excellence | कृषि उत्कृष्टता
                </div>

                <div className="flex items-center gap-4">
                    <span className="hidden md:inline">Skip to Main Content</span>
                    <div className="flex items-center gap-2 border-l pl-3 border-gray-300">
                        <a href="#" className="bg-green-900 text-white p-1 rounded-sm hover:bg-green-700 transition">
                            <FaFacebookF size={12} />
                        </a>
                        <a href="#" className="bg-green-900 text-white p-1 rounded-sm hover:bg-green-700 transition">
                            <FaTwitter size={12} />
                        </a>
                    </div>
                    <div className="flex items-center gap-1 ml-2 font-bold text-orange-500">
                        {/* <button className="border border-gray-300 bg-white px-2 hover:bg-gray-200">A-</button> */}
                        {/* <button className="border border-gray-300 bg-white px-2 hover:bg-gray-200">A</button> */}
                        {/* <button className="border border-gray-300 bg-white px-2 hover:bg-gray-200">A+</button> */}
                    </div>
                </div>
            </div>
            {/* --- Main Header (White Section with Logos) --- */}
           <div className="bg-white py-2 px-4 md:px-8 shadow-sm">
  {/* Main Container 
      Mobile: justify-start (Align Left)
      Desktop: md:justify-center (Align Center)
  */}
  <div className="container mx-auto flex flex-row justify-start md:justify-center items-center gap-4">

    {/* Content Wrapper */}
    <div className="flex flex-row items-center gap-3 md:gap-4">

      {/* 1. EMBLEM 
         (Moved to the first position so it sits on the Left on mobile) 
      */}
   {/* Added 'md:hidden' so it disappears on desktop screens */}
<div className="h-12 w-12 md:hidden flex-shrink-0">
  <div className="w-full h-full bg-red-100 border border-red-300 rounded-full flex items-center justify-center text-red-500 text-xs">
    <img 
      src="/Morvi Crop Science Logo.png" 
      alt="Emblem" 
      className="w-full h-full object-cover"
    />
  </div>
</div>

      {/* 2. Hindi Text 
         Mobile: Text Left, Items Start
         Desktop: Text Center, Items Center
      */}
      <div className="flex flex-col items-start md:items-center text-left md:text-center">
        <h1 className="text-lg md:text-2xl font-bold text-gray-800 leading-tight">MORVI CROP SCIENCE</h1>
        <p className="text-xs md:text-base text-gray-600 font-medium">Agricultural Excellence</p>
      </div>

     {/* Emblem: Added 'hidden' to hide on mobile, 'md:block' to show on desktop */}
<div className="hidden md:block h-12 w-12 md:h-16 md:w-16 flex-shrink-0">
  <div className="w-full h-full bg-red-100 border border-red-300 rounded-full flex items-center justify-center overflow-hidden">
    <img 
      src="/Morvi Crop Science Logo.png" 
      alt="Emblem" 
      className="w-full h-full object-cover"
    />
  </div>
</div>


      {/* 3. English Text 
         (Hidden on mobile, Visible on Desktop)
      */}
      <div className="hidden md:block text-center border-l md:border-l-0 border-gray-300 pl-3 md:pl-0">
        <h1 className="text-xl font-bold text-gray-800 uppercase leading-tight">
        मोरवी फ़सल विज्ञान
        </h1>
        <p className="text-base text-gray-600 font-medium leading-tight">
          कृषि उत्कृष्टता
        </p>
        {/* <p className="text-xs text-gray-500 leading-tight">
          Government of Bihar
        </p> */}
      </div>

    </div>

  </div>
</div>
            {/* --- Navigation Bar (Orange Section) --- */}
          <div className="bg-gradient-to-r from-[#ff9c00] via-[#ff8800] to-[#ff9c00] text-white relative z-50">
    <div className="container mx-auto">
        <div className="flex justify-between md:justify-start items-stretch">

            {/* 1. Home Icon (Always visible) */}
            <Link href="/" className="bg-green-900 px-5 py-3 flex items-center hover:bg-green-800 transition">
                <FaHome size={20} />
            </Link>

            {/* 2. Desktop Menu (Hidden on Mobile) */}
            <ul className="hidden md:flex flex-wrap text-[15px] font-medium items-center">
                <NavItems />
            </ul>

            {/* --- RIGHT SIDE ACTIONS (Login + Hamburger) --- */}
            {/* ml-auto pushes this section to the far right on both Mobile and Desktop */}
            <div className="flex items-center ml-auto gap-4 px-4">
                
                {/* LOGIN BUTTON */}
               {/* <button className="bg-gradient-to-r from-[#ff9c00] to-[#ff8800] hover:from-[#ff8800] hover:to-[#ff9c00] text-white px-8 py-3 rounded-full font-bold transition-all transform hover:scale-105 shadow-lg hover:shadow-xl">
                Get A Quote
              </button> */}

                {/* 3. Mobile Hamburger Button (Visible only on Mobile) */}
                <button
                    className="md:hidden flex items-center focus:outline-none hover:text-orange-200 transition"
                    onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                >
                    {isMobileMenuOpen ? <FaTimes size={24} /> : <FaBars size={24} />}
                </button>
            </div>

        </div>

        {/* 4. Mobile Menu Dropdown (Conditionally Rendered) */}
        <div className={`md:hidden overflow-hidden transition-all duration-300 ease-in-out ${isMobileMenuOpen ? 'max-h-screen opacity-100' : 'max-h-0 opacity-0'}`}>
            <ul className="flex flex-col text-sm font-medium bg-orange-600 border-t border-orange-400">
                <NavItems isMobile={true} />
            </ul>
        </div>
    </div>
</div>
        </div>
    );
};

// --- Extracted List Items to avoid code duplication ---
const NavItems = ({ isMobile }) => {
    return (
        <>
            <NavItem title="About" link="/about" hasDropdown isMobile={isMobile} />
            <NavItem title="Product" link="/product" hasDropdown isMobile={isMobile} />
            <NavItem title="Gallery" link="/gallery" hasDropdown isMobile={isMobile} />
            {/* <NavItem title="FAQ" link="/faq" isMobile={isMobile} /> */}
            {/* <NavItem title="POSH" link="#" badge="NEW" isMobile={isMobile} /> */}
            <NavItem title="Contact" link="/contact" isMobile={isMobile} />
        </>
    );
};

// --- Updated Helper Component for Nav Items ---
const NavItem = ({ title, link = "#", hasDropdown, badge, isMobile }) => {
    return (
        <li className={`relative group ${isMobile ? 'border-b border-orange-500 w-full' : 'border-r border-orange-400 last:border-none'}`}>
            <Link
                href={link}
                className={`px-4 md:px-6 py-3 flex items-center justify-between md:justify-start h-full hover:bg-orange-700 md:hover:bg-orange-600 transition whitespace-nowrap ${isMobile ? 'w-full' : ''}`}
            >
                <div className="flex items-center">
                    {title}
                    {/* Show Caret only on Desktop for dropdowns, or adjust logic for mobile accordion if needed */}
                    {hasDropdown && !isMobile && <FaCaretDown className="ml-1 text-xs opacity-80" />}
                </div>

                {/* "NEW" Badge Logic */}
                {badge && (
                    <span className={`text-[9px] bg-green-600 text-white px-1 rounded animate-pulse ${isMobile ? 'ml-2' : 'absolute top-1 right-1'}`}>
                        {badge}
                    </span>
                )}
            </Link>
        </li>
    );
};

export default Navbarr;